const STATS = {
  run:        16,
  factories:  20,
  pieces:     24973,
  kept:       24860,
  curated:    1296,
  best:       89.1,
};
STATS.withheld = STATS.kept - STATS.curated;

const fmt = n => n.toLocaleString("en-US");
const WORDS = {
  pieces:    "twenty‑four thousand nine hundred and seventy‑three",
  kept:      "twenty‑four thousand eight hundred and sixty",
  withheld:  "twenty‑three thousand five hundred and sixty‑four",
  factories: "twenty",
  curated:   "one thousand two hundred and ninety‑six",
};

document.addEventListener("DOMContentLoaded", () => {
  document.querySelectorAll("[data-stat]").forEach(el => {
    const key = el.dataset.stat;
    if (key.endsWith("-words") && WORDS[key.replace("-words", "")]) {
      el.textContent = WORDS[key.replace("-words", "")];
    } else if (STATS[key] !== undefined) {
      el.textContent = typeof STATS[key] === "number" ? fmt(STATS[key]) : STATS[key];
    }
  });
});
